(()=>{window.JM_RECOLOR_DATA=Object.assign(window.JM_RECOLOR_DATA||{},{"long/hair/green":"","long/hair/pink":"","long/hair/purple":"","long/hair/red":"","long/hair/silver":"","long/hair/teal":"","long/jacket/academy":"","long/jacket/explorer":""});window.getJapaneseMinerRecolor=window.getJapaneseMinerRecolor||((hair,part,id)=>{const value=window.JM_RECOLOR_DATA[hair+'/'+part+'/'+id];return value?'url("data:image/webp;base64,'+value+'")':'none';});})();
